async (page) => {
  // Click Villager to open shop
  await page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x: 700, y: 370});
  await page.waitForTimeout(1000);

  // Read store items from DOM while shop is open
  const storeData = await page.evaluate(() => {
    const store = document.getElementById('store');
    if (!store || window.getComputedStyle(store).display === 'none') return {open: false};

    // Get all item slots in store
    const slots = document.querySelectorAll('#store-slots-content .item-slot');
    const inventorySlots = document.querySelectorAll('#store-inventory-slots .item-slot');

    return {
      open: true,
      storeSlots: slots.length,
      inventorySlots: inventorySlots.length,
      storeHTML: document.getElementById('store-slots-content')?.innerHTML?.substring(0, 500)
    };
  });

  return JSON.stringify(storeData);
}
